import random

class PenaltyShootoutAI:
    def __init__(self, player_data):
        self.player_data = player_data
        self.preferred_foot = player_data['preferred_foot']
        self.shooting_accuracy = player_data['shooting_accuracy']
        self.feint_chance = 0.7  # Probability of performing a feint

    def decide_shot(self, goalkeeper_position):
        # Determine if the player will perform a feint
        if random.random() < self.feint_chance:
            shot_direction = self.perform_feint(goalkeeper_position)
        else:
            shot_direction = self.direct_shot(goalkeeper_position)

        return shot_direction

    def perform_feint(self, goalkeeper_position):
        # Perform a false run and change direction
        false_run_direction = 'left' if self.preferred_foot == 'left' else 'right'
