            # Perform a false run to the opposite direction
            false_run_direction = 'right' if false_run_direction == 'left' else 'left'

        # Choose a final shot direction based on the goalkeeper's position
        if goalkeeper_position == 'center':
            shot_direction = 'top' if random.random() < 0.5 else 'bottom'
        elif goalkeeper_position == 'left':
            shot_direction = 'right' if random.random() < 0.5 else 'left'
        elif goalkeeper_position == 'right':
            shot_direction = 'left' if random.random() < 0.5 else 'right'

        return shot_direction

    def direct_shot(self, goalkeeper_position):
        # Direct shot without feinting
        shot_direction = 'left' if self.preferred_foot == 'left' else 'right'

        if goalkeeper_position == 'center':
            shot_direction = 'top' if random.random() < 0.5 else 'bottom'
        elif goalkeeper_position == 'left':
            shot_direction = 'right' if random.random() < 0.5 else 'left'
        elif goalkeeper_position == 'right':
            shot_direction = 'left' if random.random() < 0.5 else 'right'

        return shot_direction

